const Q_BIOLOGY_2024_MODEL_II=[{"id": "objective>Biology>2024 Model II>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A thick layer of fat under the skin of certain mammals helps them to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lose heat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gain heat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">conserve heat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">generate heat</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A thick layer of fat, known as adipose tissue, under the skin of certain mammals acts as an insulating layer. This layer helps in conserving body heat by reducing heat loss to the environment. Fat is a poor conductor of heat, so it acts as a barrier, preventing heat from escaping the body. This insulation is particularly important for mammals living in cold environments, as it helps them maintain a stable body temperature and survive in harsh conditions.</div>", "topic": "COORDINATION AND CONTROL : HOMEOSTASIS"}, {"id": "objective>Biology>2024 Model II>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Maintaining a steady internal environment is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">co-ordination</div>", "<div style=\"font-family:Cambria;font-size:17px;\">excretion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">metabolism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">homeostasis</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Homeostasis refers to the ability of an organism to maintain a stable internal environment despite external changes. This stability is achieved through various physiological mechanisms that regulate factors such as temperature, pH, ion concentrations, and nutrient levels within narrow limits. Homeostasis is essential for the proper functioning of cells, tissues, and organs, ensuring optimal conditions for biochemical reactions and overall health.</div>", "topic": "COORDINATION AND CONTROL : HOMEOSTASIS"}, {"id": "objective>Biology>2024 Model II>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The cells that transmit messages to effectors are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sensory neurones</div>", "<div style=\"font-family:Cambria;font-size:17px;\">receptors</div>", "<div style=\"font-family:Cambria;font-size:17px;\">relay neurones</div>", "<div style=\"font-family:Cambria;font-size:17px;\">motor neurones</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Motor neurons, also known as efferent neurons, are responsible for transmitting messages from the central nervous system (brain and spinal cord) to the effectors, which are typically muscles or glands. These messages result in some kind of response or action, such as muscle contraction or gland secretion.</div>", "topic": "COORDINATION AND CONTROL : NERVOUS COORDINATION"}, {"id": "objective>Biology>2024 Model II>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The part of the brain responsible for the control of voluntary movement and interpretation of sensations is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cerebrum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cerebellum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">thalamus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">medulla oblongata</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The cerebrum, specifically the cerebral cortex, is responsible for the control of voluntary movements and the interpretation of sensations. It is the largest part of the brain and is divided into two hemispheres. The cerebral cortex contains motor areas that control voluntary movements and sensory areas that interpret sensations such as touch, pain, temperature, and pressure. Additionally, the cerebrum plays a role in higher cognitive functions such as memory, language, and reasoning.</div>", "topic": "COORDINATION AND CONTROL : NERVOUS COORDINATION"}, {"id": "objective>Biology>2024 Model II>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which letter from the flower diagram below represents sepal? <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">G</div>", "<div style=\"font-family:Cambria;font-size:17px;\">F</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">G is the sepal. The sepal is a leaf-shaped structure found in flowering plants, or angiosperms. It is found on the outermost part of the flower, and like a petal, a sepal is considered to be a modified leaf. However, sepals are more likely to be confused with leaves since they are typically, but not always, green. They are also often covered with tiny hairs, and are directly attached to the stem as they are the first part of the flower to develop.</div>", "topic": "REPRODUCTION : ASEXUAL REPRODUCTION~~REPRODUCTION : SEXUAL REPRODUCTION"}, {"id": "objective>Biology>2024 Model II>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which arrangement shows the correct pathway of impulse transmission?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dendrites → cell body → axon → synaptic knobs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cell body → axon → dendrites → synaptic knobs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">axon → cell body → dendrites → synaptic knobs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">synaptic knobs → axon → cell body → dendrites </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct pathway of impulse transmission in a neuron is from the dendrites, which receive signals from other neurons or sensory receptors, to the cell body (soma), where these signals are integrated, to the axon, which transmits the signal away from the cell body, and finally to the synaptic knobs (axon terminals), which release neurotransmitters to communicate with the next neuron or effector cell.</div>", "topic": "COORDINATION AND CONTROL : NERVOUS COORDINATION"}, {"id": "objective>Biology>2024 Model II>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Co-ordination is achieved in the body of mammals through the action of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">endocrine and nervous systems</div>", "<div style=\"font-family:Cambria;font-size:17px;\">skeletal and nervous systems</div>", "<div style=\"font-family:Cambria;font-size:17px;\">muscular and nervous system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">circulatory and nervous system</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Coordination in the body of mammals, as well as in other organisms, is achieved through the combined action of the endocrine and nervous systems. <br/>  <br/> The endocrine system consists of glands that secrete hormones directly into the bloodstream. These hormones travel throughout the body and regulate various physiological processes, such as growth, metabolism, reproduction, and responses to stress. <br/> The nervous system consists of the brain, spinal cord, and nerves. It coordinates rapid responses to stimuli from the internal and external environment. The nervous system receives sensory input, processes and integrates this information, and generates appropriate motor responses. <br/> Together, the endocrine and nervous systems work in concert to maintain homeostasis, coordinate responses to environmental changes, regulate bodily functions, and facilitate communication between different parts of the body.</div>", "topic": "COORDINATION AND CONTROL : HORMONAL CONTROL"}, {"id": "objective>Biology>2024 Model II>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The region of acutest vision is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cones</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fovea</div>", "<div style=\"font-family:Cambria;font-size:17px;\">retina</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rods</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The fovea is the region of the retina in the eye that contains the highest concentration of cone cells, which are photoreceptor cells responsible for color vision and visual acuity (sharpness of vision). The fovea is located at the center of the macula and is responsible for the sharpest vision and highest visual acuity. It is specialized for detailed central vision and is primarily involved in tasks requiring high-resolution vision, such as reading, driving, and recognizing faces.</div>", "topic": "COORDINATION AND CONTROL : THE SENSE ORGANS"}, {"id": "objective>Biology>2024 Model II>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which part of the ear is responsible for the maintenance of balance?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Ossicles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cochlea</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Perilymph</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Semicircular canal</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The semicircular canals are part of the inner ear and are responsible for the maintenance of balance and orientation in space. They are filled with fluid and lined with sensory hair cells that detect rotational movements of the head in three dimensions: side to side (horizontal plane), up and down (sagittal plane), and tilting movements (lateral plane). When the head moves, the fluid within the semicircular canals also moves, stimulating the hair cells and sending signals to the brain about the direction and speed of the head movement, which helps in maintaining balance and coordinating movements.</div>", "topic": "COORDINATION AND CONTROL : THE SENSE ORGANS"}, {"id": "objective>Biology>2024 Model II>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which structure shown on the diagram aids cell movement? <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">B</div>", "<div style=\"font-family:Cambria;font-size:17px;\">F</div>", "<div style=\"font-family:Cambria;font-size:17px;\">G</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The labelled part G on the diagram represent the flagellum which aids the cell movement</div>", "topic": "CLASSIFICATION OF LIVING THINGS"}, {"id": "objective>Biology>2024 Model II>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The menstrual cycle is controlled by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ovulation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ovum maturation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gonadotropins and ovarian hormones</div>", "<div style=\"font-family:Cambria;font-size:17px;\">copulation</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The menstrual cycle, which is the monthly series of changes in a woman's body that involves the maturation of an egg (ovum) and preparation of the uterus for possible pregnancy, is primarily controlled by a complex interplay of hormones. <br/>  <br/> Gonadotropins, including follicle-stimulating hormone (FSH) and luteinizing hormone (LH), are released from the pituitary gland and stimulate the ovaries to produce estrogen and progesterone. <br/> Ovarian hormones, primarily estrogen and progesterone, are produced by the ovaries in response to the stimulation from gonadotropins. These hormones regulate the growth and maturation of the ovarian follicles, the release of the mature egg during ovulation, and the changes in the uterine lining.</div>", "topic": "REPRODUCTION : SEXUAL REPRODUCTION"}, {"id": "objective>Biology>2024 Model II>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A true fruit develops from</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fertilized ovary </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ovary and ovule </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the ovule only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the flower only</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A true fruit develops from the fertilized ovary of a flower after pollination and fertilization have occurred. After fertilization, the ovary undergoes changes and develops into a fruit, which contains seeds formed from the fertilized ovules. The seeds are enclosed within the fruit, and together, they represent the mature ovary and its contents.</div>", "topic": "FRUITS"}, {"id": "objective>Biology>2024 Model II>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of a viviparous animal is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an ant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a hen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a rat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a lizard</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Viviparity is a reproductive mode in which offspring develop within the mother's body and are born alive. In viviparous animals, embryos receive nourishment directly from the mother through a placenta or similar structure. Rats are viviparous mammals. They give birth to live young after a gestation period during which the embryos develop inside the mother's uterus.</div>", "topic": "REPRODUCTION : REPRODUCTION IN MAMMALS"}, {"id": "objective>Biology>2024 Model II>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The food storage tissue for the embryo in the maize grain is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">embryo</div>", "<div style=\"font-family:Cambria;font-size:17px;\">scutellum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">caruncle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">endosperm</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a maize grain (corn kernel), the endosperm serves as the primary food storage tissue for the developing embryo. The endosperm is a nutrient-rich tissue surrounding the embryo within the seed. It provides carbohydrates, proteins, and other essential nutrients to the developing embryo, allowing it to grow and develop until it can photosynthesize and obtain nutrients independently after germination.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : STEM"}, {"id": "objective>Biology>2024 Model II>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The buzzard has a short, hooked beak. Based on the shape and size of its beak, which type of food does the buzzard most likely eat? <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">parasites living within tree bark</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ant burrowed in mud</div>", "<div style=\"font-family:Cambria;font-size:17px;\">remains of small mammals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">berries growing on bushes</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The short, hooked beak of the buzzard is particularly suited for tearing meat from their prey. This beak shape is common among birds of prey (raptors), and it allows them to effectively hunt and consume their prey. So, based on the shape and size of its beak, the buzzard most likely eats small mammals, birds, and insects</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2024 Model II>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The yellow and black stripes on the body of wasps is an example of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">counter shading</div>", "<div style=\"font-family:Cambria;font-size:17px;\">warning coloration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mimicry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cryptic coloration</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The yellow and black stripes on the body of wasps serve as an example of warning coloration, also known as aposematism. Warning coloration is a type of color pattern that advertises to potential predators that the animal is toxic, harmful, or otherwise defended. In the case of wasps, their bright yellow and black stripes often signal to predators that they are capable of stinging and may deliver a painful or dangerous venom if threatened.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>2024 Model II>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main force that regularly produces evolutionary change is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mutation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">genetic drift</div>", "<div style=\"font-family:Cambria;font-size:17px;\">genetic variation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">natural selection</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Natural selection is the main force that regularly produces evolutionary change in populations over time. It is a process by which individuals with traits that are better adapted to their environment tend to survive and reproduce more successfully than those with less favorable traits. As a result, favorable traits become more common in the population over successive generations, leading to evolutionary change.</div>", "topic": "EVOLUTION : THEORIES OF EVOLUTION"}, {"id": "objective>Biology>2024 Model II>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The diagram below shows a monohybrid cross for plant height where T is the allele for tallness, and t for shortness. Which of the following statements about this cross is not true? <br/> Parents TT x tt <br/>                    -------------↓ <br/> Offspring Tt</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Both parents are homozygotes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">All the offspring are short</div>", "<div style=\"font-family:Cambria;font-size:17px;\">All the offspring are heterozygotes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The parents are hybrid</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the given monohybrid cross between the parents TT (tall) and tt (short), where T represents the allele for tallness and t for shortness, the expected genotype of the offspring is Tt, which represents a heterozygous genotype. However, the phenotype expressed by the offspring will be tall because the dominant allele (T) masks the expression of the recessive allele (t). This statement is false. The offspring (Tt) will be tall because the dominant allele (T) masks the expression of the recessive allele (t), resulting in a tall phenotype.</div>", "topic": "HEREDITY : APPLICATION OF THE PRINCIPLES OF HEREDITY"}, {"id": "objective>Biology>2024 Model II>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The tendency for two or more genes to segregate together in a cross is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">co-dominace</div>", "<div style=\"font-family:Cambria;font-size:17px;\">incomplete dominance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">polygenic inheritance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">linkage</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Linkage refers to the tendency of two or more genes to be inherited together because they are located close to each other on the same chromosome. During meiosis, the process by which chromosomes are separated into gametes, linked genes tend to stay together and are less likely to undergo independent assortment.</div>", "topic": "HEREDITY : APPLICATION OF THE PRINCIPLES OF HEREDITY"}, {"id": "objective>Biology>2024 Model II>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which structure is represented by the letter A on the diagram of the female reproductive system? <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ovary</div>", "<div style=\"font-family:Cambria;font-size:17px;\">uterus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">endometrium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fallopian tube</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The fallopian tube(s) – also known as \"uterine tubes\" or \"oviducts\"- are two hollow ducts in the female reproduction system where oocyte fertilization occurs. </div>", "topic": "REPRODUCTION : SEXUAL REPRODUCTION"}, {"id": "objective>Biology>2024 Model II>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the structural level of organization of a Paramecium?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Tissue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Organ</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cellular</div>", "<div style=\"font-family:Cambria;font-size:17px;\">System</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Paramecium is a unicellular organism, meaning it is made up of just one cell. All life processes—such as feeding, reproduction, and movement—are carried out within this single cell. This places it at the cellular level of organization. Multicellular organisms have higher levels of organization such as tissues, organs, and systems.</div>", "topic": "CLASSIFICATION OF LIVING THINGS"}, {"id": "objective>Biology>2024 Model II>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following organisms is one-celled and free-living?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Volvox</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Spirogyra</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rhizopus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chlamydomonas</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Chlamydomonas is a one-celled and free-living organism. It is a type of green algae that is found in stagnant water and on damp soil. Unlike Volvox, Spirogyra, and Rhizopus, which are multicellular, Chlamydomonas is unicellular. It is capable of photosynthesis, and it can move using its two flagella. It is considered free-living because it does not rely on a host or other organism for survival.</div>", "topic": "CLASSIFICATION OF LIVING THINGS"}, {"id": "objective>Biology>2024 Model II>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Carbon dioxide enters the stomata during photosynthesis through the process known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">osmosis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">active transport</div>", "<div style=\"font-family:Cambria;font-size:17px;\">diffusion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inhalation</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">During photosynthesis, carbon dioxide enters the stomata through the process known as diffusion. Diffusion is the movement of molecules from an area of higher concentration to an area of lower concentration. In this case, the concentration of carbon dioxide is usually higher in the atmosphere than inside the leaf, so it diffuses into the stomata.</div>", "topic": "NUTRITION : PHOTOSYNTHESIS"}, {"id": "objective>Biology>2024 Model II>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not a tissue found in plants?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Epidermis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Phloem</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Xylem</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dermis</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the context of plant biology, the dermis is not a tissue found in plants. The dermis is a layer of skin found in animals, not plants. On the other hand, Epidermis, Phloem, and Xylem are all types of tissues found in plants. The Epidermis is the outermost layer of cells covering the plant, Phloem is the vascular tissue in plants which conducts sugars and other metabolic products downwards from the leaves, and Xylem is the vascular tissue in plants that conducts water and dissolved nutrients upwards from the root and also helps to form the woody element in the stem.</div>", "topic": "COORDINATION AND CONTROL : HOMEOSTASIS"}, {"id": "objective>Biology>2024 Model II>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The series of changes that occur in a seed by which the embryo develops into a seedling is known as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fertilization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gametogenesis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pollination</div>", "<div style=\"font-family:Cambria;font-size:17px;\">germination</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The series of changes that occur in a seed by which the embryo develops into a seedling is known as germination. Germination is the process by which an organism grows from a seed or similar structure. The most common example of germination is the sprouting of a seedling from a seed of an angiosperm or gymnosperm. In contrast, fertilization is the fusion of gametes to initiate the development of a new individual organism. Gametogenesis is a biological process by which diploid or haploid precursor cells undergo cell division and differentiation to form mature haploid gametes. Pollination is the transfer of pollen from a male part of a plant to a female part of a plant, later enabling fertilisation and the production of seeds, most often by an animal or by wind.</div>", "topic": "GROWTH : GERMINATION OF SEEDS AND CONDITION NECESSARY FOR GERMINATION OF SEEDS"}, {"id": "objective>Biology>2024 Model II>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which animal lives in mutual association with algae that supply it with oxygen and food?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Coral</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Planaria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hydra</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tapeworm</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hydra hosts green algae inside its cells. The algae perform photosynthesis, producing oxygen and sugars for the hydra. In exchange, the hydra provides the algae with shelter and access to light. This is a mutualistic symbiosis, where both organisms benefit.</div>", "topic": "ECOLOGY : SYMBIOTIC INTERACTIONS OF PLANTS AND ANIMALS"}, {"id": "objective>Biology>2024 Model II>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">At the end of photosynthesis, the green leaf is tested for starch and not glucose, because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the glucose is used up immediately to provide energy for the needs of the leaf</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the glucose formed is immediately converted to starch</div>", "<div style=\"font-family:Cambria;font-size:17px;\">starch is stored only in leaves</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there are no chemicals for glucose test in leaves</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">During photosynthesis, plants convert carbon dioxide and water into glucose. This glucose is then immediately converted into starch for storage. Starch is a polysaccharide, a large molecule made up of many glucose units. It is more efficient for plants to store glucose in the form of starch because it is less reactive and takes up less space due to its structure. Therefore, at the end of photosynthesis, the leaf is tested for starch and not glucose because the glucose formed is immediately converted to starch.</div>", "topic": "NUTRITION : PHOTOSYNTHESIS"}, {"id": "objective>Biology>2024 Model II>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which natural process helps reduce the amount of carbon dioxide in the air?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Decomposition of dead animals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Combustion of coal and oil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Photosynthesis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Release of gases from volcanoes</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Photosynthesis is carried out by green plants and certain microorganisms. They use chlorophyll to trap sunlight and convert carbon dioxide from the atmosphere into glucose, releasing oxygen in the process. This removes CO₂ from the air. In contrast, decomposition, fuel burning, and volcanic eruptions release carbon dioxide rather than absorb it.</div>", "topic": "NUTRITION : PHOTOSYNTHESIS"}, {"id": "objective>Biology>2024 Model II>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following conditions is not necessary for photosynthesis to occur in plants?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">There must be light</div>", "<div style=\"font-family:Cambria;font-size:17px;\">There must be xylem tissue used to conduct water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">There must be chlorophyll to trap radiant energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Carbondioxide must be present</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Photosynthesis is the process by which green plants and some other organisms use sunlight to synthesize foods with the aid of chlorophyll pigments. The necessary conditions for photosynthesis to occur include light, chlorophyll, and carbon dioxide. However, the presence of xylem tissue is not a direct requirement for photosynthesis. Xylem tissue is involved in the transport of water from the roots to other parts of the plant, but it is not a condition for photosynthesis to occur. Therefore, the statement 'There must be xylem tissue used to conduct water' is not a necessary condition for photosynthesis.</div>", "topic": "NUTRITION : PHOTOSYNTHESIS"}, {"id": "objective>Biology>2024 Model II>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">To what Kingdom does the organism pictured belong? <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Fungi</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Plantae</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Protista</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Animalia</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fungi are eukaryotic organisms that include microorganisms such as yeasts, moulds and mushrooms. These organisms are classified under kingdom fungi. <br/>  <br/> The organisms found in Kingdom fungi contain a cell wall and are omnipresent. They are classified as heterotrophs among the living organisms.</div>", "topic": "CLASSIFICATION OF LIVING THINGS"}, {"id": "objective>Biology>2024 Model II>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is characteristics of a swamp?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Vegetation with stratified arrangement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mesophytes with broad leaves</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The ground is flooded most of the time</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Predominance of climbing plants</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A swamp is a wetland that is forested, meaning it is covered with water for most of the time. Therefore, the characteristic of a swamp is that the ground is flooded most of the time. The other options do not accurately describe a swamp. Stratified arrangement of vegetation is more characteristic of a rainforest, mesophytes with broad leaves are plants that live in an environment with a moderate amount of water, and predominance of climbing plants is more characteristic of a tropical rainforest.</div>", "topic": "HABITAT"}, {"id": "objective>Biology>2024 Model II>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A region has less than 250 mm of rainfall per year, plants are widely spaced, and the temperature is extremely hot in the day but very cold at night. This region is most likely a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Tropical rainforest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Savanna grassland</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Desert</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mangrove swamp</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Deserts experience very low annual rainfall, sparse vegetation, and extreme temperature fluctuations between day and night. The lack of water limits plant growth, and low humidity causes rapid cooling after sunset. Tropical rainforests and swamps are wetter, while savannas have more vegetation and seasonal rainfall.</div>", "topic": "HABITAT"}, {"id": "objective>Biology>2024 Model II>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is the correct chain for the organism found in an aquatic community?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Paramecium, Phytoplankton, Prawn, Waterflea, Tilapia, Shark</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Waterflea, Paramecium, Phytoplankton, Prawn, Tilapia, Shark</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Phytoplankton, Waterflea, Paramecium, Prawn, Shark, `tilapia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Phytoplankton, Paramecium, Waterflea, Prawn, Tilapia, Shark</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In an aquatic community, the food chain typically starts with Phytoplankton, which are primary producers. They are eaten by Paramecium (a type of zooplankton), which in turn are eaten by Waterfleas. Waterfleas are then consumed by Prawns, which are eaten by Tilapia (a type of fish). Finally, Sharks, being apex predators, eat Tilapia. Therefore, the correct chain is Phytoplankton, Paramecium, Waterflea, Prawn, Tilapia, Shark.</div>", "topic": "HABITAT"}, {"id": "objective>Biology>2024 Model II>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a food chain the position occupied by an organism is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the trophic level</div>", "<div style=\"font-family:Cambria;font-size:17px;\">energy level</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the feeding level</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the habitat level</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a food chain, the position occupied by an organism is called the trophic level. A trophic level of an organism is the position it occupies in a food chain. The primary producers (plants) occupy the first trophic level, primary consumers (herbivores) occupy the second trophic level, secondary consumers (carnivores) occupy the third trophic level, and so on. The other options do not accurately describe the position of an organism in a food chain.</div>", "topic": "ECOLOGY : FOOD CHAINS FOOD WEBS AND TROPHIC LEVELS"}, {"id": "objective>Biology>2024 Model II>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these statements about food chain is not correct?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Animals in the chain are consumers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A food chain usually begins with a green plant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">All organisms in a food chain are animals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Living things are dependent on one another</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A food chain represents the flow of energy and nutrients in an ecosystem, starting from producers (usually green plants) and moving up to different levels of consumers (animals). The statement 'All organisms in a food chain are animals' is incorrect because a food chain starts with plants (producers) which are not animals. They use sunlight to produce food through a process called photosynthesis. Herbivores (plant-eating animals) then eat these plants, and carnivores (meat-eating animals) eat the herbivores. Hence, a food chain includes both plants and animals.</div>", "topic": "ECOLOGY : FOOD CHAINS FOOD WEBS AND TROPHIC LEVELS"}, {"id": "objective>Biology>2024 Model II>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these is not applicable to the circulation of water- in nature?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Water removed from oceans are Permanently lost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Water constantly evaporates from the seas, rivers, lakes and soil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Water vapour rises. cools, condenses and precipitates as rain and dew</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Water is absorbed by plants and animals from their external environment</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The statement 'Water removed from oceans are Permanently lost' is not applicable to the circulation of water in nature. This is because the water cycle, also known as the hydrologic cycle, is a continuous process where water evaporates, travels into the air and becomes part of a cloud, falls down to earth as precipitation, and then evaporates again. This cycle is a closed system, meaning no water is permanently lost from the oceans. The other options correctly describe processes involved in the water cycle.</div>", "topic": "NUTRITION : PLANT NUTRITION"}, {"id": "objective>Biology>2024 Model II>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not an outcome of ecological succession?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">There is a progressive change in species structure, organic matter and energy flow</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The climax stage consists of a comparatively long lasting species composition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">There is no dynamic equilibrium between the community and habitat in the climax stage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Communities occurring later in the sequence of succession are more complex</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ecological succession is the process of change in the species structure of an ecological community over time. The climax stage in ecological succession is characterized by a stable community which has reached a steady state, or dynamic equilibrium, with the environment. This means that there is indeed a dynamic equilibrium between the community and habitat in the climax stage.</div>", "topic": "THE ECOLOGY OF POPULATIONS : ECOLOGICAL SUCCESSION"}, {"id": "objective>Biology>2024 Model II>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The following are useful measures for conserving forest except</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">preventing and controlling accidental forest fire</div>", "<div style=\"font-family:Cambria;font-size:17px;\">encouraging the use of charcoal for industrial and domestic purposes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">combating and preventing plant diseases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reafforestation of depleted forest</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct answer is 'encouraging the use of charcoal for industrial and domestic purposes'. This is because the production of charcoal involves cutting down trees and burning them, which contributes to deforestation. Deforestation is the opposite of forest conservation. The other options involve measures that help to protect and restore forests. Preventing and controlling accidental forest fires helps to prevent the destruction of forests. Combating and preventing plant diseases helps to keep the trees in the forest healthy. Reafforestation of depleted forest involves planting new trees in areas where the forest has been cut down, which helps to restore the forest.</div>", "topic": "HUMANS AND ENVIRONMENT : CONSERVATION OF NATURAL RESOURCES"}, {"id": "objective>Biology>2024 Model II>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The following practices are aimed at soil conservation except</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">contour ridging</div>", "<div style=\"font-family:Cambria;font-size:17px;\">application of manures</div>", "<div style=\"font-family:Cambria;font-size:17px;\">strip cropping</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bush clearing</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Soil conservation involves practices that are aimed at preventing soil erosion or degradation. Contour ridging, application of manures, and strip cropping are all practices that help in soil conservation. Contour ridging helps in reducing the speed of water flow, thus reducing soil erosion. Application of manures improves the soil structure and its capacity to hold water, thus reducing soil erosion. Strip cropping involves growing crops in a systematic way in rows or strips which helps in reducing soil erosion. On the other hand, bush clearing, which involves removing vegetation cover, can lead to soil erosion as it exposes the soil to wind and water. Therefore, bush clearing is not aimed at soil conservation.</div>", "topic": "HUMANS AND ENVIRONMENT : CONSERVATION OF NATURAL RESOURCES"}, {"id": "objective>Biology>2024 Model II>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is an example of discontinuous variation?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Height</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Size of head</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Blood group</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Skin colour</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Discontinuous variation refers to the variation in characteristics that have a definite form. These characteristics are controlled by a single pair of genes. Examples of discontinuous variation include blood group, ability to roll the tongue, etc. In this case, the blood group is an example of discontinuous variation because there are distinct categories (A, B, AB, O) and no intermediates.</div>", "topic": "VARIATION IN POPULATION : APPLICATION OF VARIATION"}];
